#!/usr/bin/python3

import os

def read_book():
    path = os.environ['BOOK_PATH']
    book = open(path)

    summary = generate_summary(book.read())

    return summary

def generate_summary(text):
    os.system(f"./summary.sh '{text}'")

read_book()

